class Solution {
    private static final int MOD = (int) 1e9 + 7;
    public int peopleAwareOfSecret(int n, int delay, int forget) {
        int[] dp = new int[n + 1];
        dp[1] = 1;
        int share = 0;
        for (int i = 2; i <= n; i++) {
            if (i > delay) {
                share = (share + dp[i - delay]) % MOD;
            }
            if (i > forget) {
                share = (share - dp[i - forget] + MOD) % MOD;
            }
            dp[i] = share;
        }
        int sum = 0;
        for (int i = Math.max(1, n - forget + 1); i <= n; i++) {
            sum = (sum + dp[i]) % MOD;
        }
        return sum;
    }
}
